const input = $input.first().json;
const query = (input.query || input.message || input.text || '').trim();
const chatId = (input.chatId || input.chat_id || '').toString();
const params = input.params || {};
const now = new Date(new Date().toLocaleString('en-US', { timeZone: 'America/Bogota' }));
const today = now.toLocaleDateString('es-ES');
const hour = now.getHours().toString().padStart(2,'0') + ':' + now.getMinutes().toString().padStart(2,'0');
return [{ json: { query, chatId, params, today, hour } }];

const agentRaw = $input.first().json;
const parser = $('📦 Parser').first().json;

let ai = {};
try {
  let text = agentRaw.text || agentRaw.output || agentRaw.message || '';
  if (typeof text === 'object') { ai = text; }
  else {
    text = text.replace(/[`]{3}json\s*/gi, '').replace(/[`]{3}\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) ai = JSON.parse(m[0]);
  }
} catch(e) { ai = { action: 'search_files' }; }

const p = ai.params || {};

return [{ json: {
  action: ai.action || 'search_files',
  intent_description: ai.intent_description || '',
  confidence: ai.confidence || 'medium',
  search_query: p.search_query || p.file_name || '',
  file_name: p.file_name || '',
  folder_name: p.folder_name || '',
  title: p.title || '',
  content: p.content || '',
  email: p.email || '',
  role: p.role || 'reader',
  dest_folder: p.dest_folder || '',
  topic: p.topic || '',
  depth: p.depth || 'intermedio',
  sheet_tab: p.sheet_tab || '',
  query: parser.query,
  chatId: parser.chatId,
  today: parser.today,
  hour: parser.hour
} }];

const files = ($input.first().json.files || []);
const q = $('🔗 Bridge').first().json.search_query;
if (!files.length) return [{ json: { _action: 'search_files', found: 0, query: q, files: [], summary: 'No se encontraron archivos con "' + q + '".' } }];
const list = files.map(f => ({ name: f.name, type: f.mimeType?.includes('folder') ? '📂 Carpeta' : f.mimeType?.includes('document') ? '📝 Doc' : f.mimeType?.includes('spreadsheet') ? '📊 Sheet' : f.mimeType?.includes('pdf') ? '📕 PDF' : '📄 Archivo', id: f.id, link: f.webViewLink || '', modified: f.modifiedTime ? new Date(f.modifiedTime).toLocaleDateString('es-ES') : '' }));
return [{ json: { _action: 'search_files', found: files.length, query: q, files: list, summary: 'Encontré ' + files.length + ' archivo(s): ' + list.map(f => f.name).join(', ') } }];

const files = ($input.first().json.files || []);
const fn = $('🔗 Bridge').first().json.folder_name || 'root';
const folders = files.filter(f => f.mimeType === 'application/vnd.google-apps.folder');
const docs = files.filter(f => f.mimeType !== 'application/vnd.google-apps.folder');
const items = files.map(f => ({ name: f.name, type: f.mimeType?.includes('folder') ? '📂' : f.mimeType?.includes('document') ? '📝' : f.mimeType?.includes('spreadsheet') ? '📊' : f.mimeType?.includes('pdf') ? '📕' : '📄', id: f.id }));
return [{ json: { _action: 'list_folder', totalItems: files.length, folderCount: folders.length, fileCount: docs.length, items, folderName: fn, summary: fn + ': ' + files.length + ' items (' + folders.length + ' carpetas, ' + docs.length + ' archivos)' } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'read_doc', summary: 'Doc no encontrado: ' + $('🔗 Bridge').first().json.file_name } }];
return [{ json: { docId: files[0].id, docName: files[0].name } }];

const doc = $input.first().json;
const docName = $('🔧 Resolve Doc').first().json.docName || doc.title || 'Documento';
let text = '';
try {
  if (doc.body && doc.body.content) {
    for (const el of doc.body.content) {
      if (el.paragraph && el.paragraph.elements) {
        for (const e of el.paragraph.elements) {
          if (e.textRun && e.textRun.content) text += e.textRun.content;
        }
      }
      if (el.table) {
        for (const row of (el.table.tableRows || [])) {
          for (const cell of (row.tableCells || [])) {
            for (const c of (cell.content || [])) {
              if (c.paragraph) {
                for (const e of (c.paragraph.elements || [])) {
                  if (e.textRun) text += e.textRun.content;
                }
                text += ' | ';
              }
            }
          }
          text += '\n';
        }
      }
    }
  }
} catch(e) { text = 'Error leyendo: ' + e.message; }
const max = 3000;
const trunc = text.length > max;
if (trunc) text = text.substring(0, max);
return [{ json: { _action: 'read_doc', title: docName, content: text.trim(), charCount: text.length, truncated: trunc, summary: 'Doc "' + docName + '": ' + text.length + ' chars' + (trunc ? ' (truncado)' : '') } }];

const createRes = $('📝 Create Doc').first().json;
const title = $('🔗 Bridge').first().json.title || 'Nuevo Doc XUS';
const docId = createRes.documentId || '';
return [{ json: { _action: 'create_doc', created: true, title, documentId: docId, link: 'https://docs.google.com/document/d/' + docId + '/edit', summary: '✅ Doc "' + title + '" creado → https://docs.google.com/document/d/' + docId + '/edit' } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'delete_file', summary: 'Archivo no encontrado: ' + $('🔗 Bridge').first().json.file_name } }];
return [{ json: { fileId: files[0].id, fileName: files[0].name } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'share_file', summary: 'Archivo no encontrado' } }];
return [{ json: { fileId: files[0].id, fileName: files[0].name, link: files[0].webViewLink || '' } }];

const r = $('🔧 Resolve Share').first().json;
const b = $('🔗 Bridge').first().json;
return [{ json: { _action: 'share_file', shared: true, fileName: r.fileName, email: b.email, role: b.role, link: r.link, summary: '✅ "' + r.fileName + '" compartido con ' + b.email + ' (' + b.role + ').' } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'move_file', summary: 'Archivo no encontrado' } }];
return [{ json: { fileId: files[0].id, fileName: files[0].name, oldParents: (files[0].parents || []).join(',') } }];

const fileRes = $('🔧 Resolve File').first().json;
const folders = ($input.first().json.files || []);
if (!folders.length) return [{ json: { error: true, _action: 'move_file', summary: 'Carpeta destino no encontrada' } }];
return [{ json: { fileId: fileRes.fileId, fileName: fileRes.fileName, folderId: folders[0].id, folderName: folders[0].name, oldParents: fileRes.oldParents } }];

const r = $input.first().json;
const topic = $('🔗 Bridge').first().json.topic;
const content = r.output || r.text || r.response || 'Investigación completada';
return [{ json: { title: 'Research XUS — ' + topic, content, topic } }];

const doc = $('📝 Create Research Doc').first().json;
const prep = $('📝 Prep Research').first().json;
const docId = doc.documentId || '';
return [{ json: { _action: 'research', researched: true, topic: prep.topic, documentId: docId, link: 'https://docs.google.com/document/d/' + docId + '/edit', preview: prep.content.substring(0, 500), summary: '✅ Research "' + prep.topic + '" → https://docs.google.com/document/d/' + docId + '/edit' } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'update_doc', summary: 'Doc no encontrado: ' + $('🔗 Bridge').first().json.file_name } }];
return [{ json: { docId: files[0].id, docName: files[0].name } }];

const doc = $input.first().json;
let endIdx = 1;
for (const el of (doc.body?.content || [])) {
  if (el.endIndex && el.endIndex > endIdx) endIdx = el.endIndex;
}
return [{ json: { docId: doc.documentId, docName: doc.title, endIndex: endIdx - 1 } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'read_sheet', summary: 'Sheet no encontrado' } }];
return [{ json: { sheetId: files[0].id, sheetName: files[0].name } }];

const data = $input.first().json;
const values = data.values || [];
const sName = $('🔧 Resolve Sheet').first().json.sheetName;
if (!values.length) return [{ json: { _action: 'read_sheet', sheetName: sName, totalRows: 0, headers: [], content: 'Hoja vacía.', summary: 'Sheet "' + sName + '" está vacío.' } }];
const headers = values[0] || [];
const rows = values.slice(1);
let preview = 'Columnas: ' + headers.join(' | ') + '\n\n';
const max = Math.min(rows.length, 20);
for (let i = 0; i < max; i++) preview += rows[i].join(' | ') + '\n';
if (rows.length > 20) preview += '... y ' + (rows.length - 20) + ' filas más';
return [{ json: { _action: 'read_sheet', sheetName: sName, totalRows: rows.length, headers, content: preview, summary: 'Sheet "' + sName + '": ' + rows.length + ' filas, ' + headers.length + ' columnas' } }];

const files = ($input.first().json.files || []);
if (!files.length) return [{ json: { error: true, _action: 'copy_file', summary: 'Archivo no encontrado' } }];
return [{ json: { fileId: files[0].id, fileName: files[0].name } }];

const orig = $('🔧 Resolve Copy').first().json;
const copy = $input.first().json;
return [{ json: { _action: 'copy_file', copied: true, originalName: orig.fileName, copyName: copy.name, copyId: copy.id, link: copy.webViewLink || '', summary: '✅ "' + orig.fileName + '" copiado como "' + copy.name + '".' } }];

const bridge = $('🔗 Bridge').first().json;
const data = $input.first().json;

if (data._action && data.summary) {
  return [{ json: { action: data._action, intent_description: bridge.intent_description, query: bridge.query, chatId: bridge.chatId, today: bridge.today, hour: bridge.hour, summary: data.summary, data, confidence: bridge.confidence } }];
}

return [{ json: { action: bridge.action, intent_description: bridge.intent_description, query: bridge.query, chatId: bridge.chatId, today: bridge.today, hour: bridge.hour, summary: data.summary || 'Acción procesada.', data, confidence: bridge.confidence } }];

