const raw = $input.first().json;
const builder = $('📊 Response Builder').first().json;
let final;
try {
  let text = raw.text || raw.output || raw.message || '';
  if (typeof text === 'object' && text.textResponse) { final = text; }
  else {
    if (typeof text !== 'string') text = JSON.stringify(text);
    text = text.replace(/[`]{3}json\s*/gi, '').replace(/[`]{3}\s*/gi, '').trim();
    const m = text.match(/\{[\s\S]*\}/);
    if (m) final = JSON.parse(m[0]); else throw new Error('No JSON');
  }
} catch(e) {
  final = { textResponse: '✅ Procesado\n\n' + (builder.summary || 'Acción ejecutada.'), toolResponse: builder.summary || 'Drive procesado' };
}
return [{ json: { textResponse: final.textResponse || builder.summary, toolResponse: final.toolResponse || 'Drive procesado', action: builder.action, data: builder.data, chatId: builder.chatId, success: true } }];
